import{_ as s,o as n,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"CAT-03. 시스템 운영 & DevOps","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/system-ops.md","filePath":"hermes/benchmark/system-ops.md","lastUpdated":1781092690000}'),e={name:"hermes/benchmark/system-ops.md"};function i(t,a,c,o,r,d){return n(),p("div",null,[...a[0]||(a[0]=[l(`<h1 id="cat-03-시스템-운영-devops" tabindex="-1">CAT-03. 시스템 운영 &amp; DevOps <a class="header-anchor" href="#cat-03-시스템-운영-devops" aria-label="Permalink to &quot;CAT-03. 시스템 운영 &amp; DevOps&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 인프라 구성, CI/CD, 트러블슈팅 등 <strong>운영 영역</strong>의 작업을 수행할 수 있는가?</p></blockquote><h2 id="난이도-범례" tabindex="-1">난이도 범례 <a class="header-anchor" href="#난이도-범례" aria-label="Permalink to &quot;난이도 범례&quot;">​</a></h2><table tabindex="0"><thead><tr><th>레벨</th><th>의미</th><th>예상 소요</th></tr></thead><tbody><tr><td>⭐</td><td>기초 — 단일 설정 파일</td><td>2~3분</td></tr><tr><td>⭐⭐</td><td>중급 — 복수 구성요소 연동</td><td>3~5분</td></tr><tr><td>⭐⭐⭐</td><td>고급 — 아키텍처 수준 설계</td><td>5~10분</td></tr></tbody></table><hr><h2 id="so-01-docker-멀티스테이지-빌드" tabindex="-1">SO-01. Docker 멀티스테이지 빌드 ⭐⭐ <a class="header-anchor" href="#so-01-docker-멀티스테이지-빌드" aria-label="Permalink to &quot;SO-01. Docker 멀티스테이지 빌드 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>실전 수준의 Dockerfile 작성 능력을 평가한다.</p><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Next.js 14 앱을 위한 프로덕션용 Dockerfile을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>요구사항:</span></span>
<span class="line"><span>- 멀티스테이지 빌드 (3단계: deps, build, runner)</span></span>
<span class="line"><span>- 최종 이미지 크기 200MB 이하 목표 (alpine 기반)</span></span>
<span class="line"><span>- non-root 사용자로 실행</span></span>
<span class="line"><span>- standalone 모드 빌드 (next.config.js에 output: &#39;standalone&#39;)</span></span>
<span class="line"><span>- 환경변수: 빌드타임 (NEXT_PUBLIC_*) vs 런타임 (DATABASE_URL 등) 구분</span></span>
<span class="line"><span>- 헬스체크 엔드포인트 (/api/health → 200 OK) 포함</span></span>
<span class="line"><span>- .dockerignore 파일도 함께 생성</span></span>
<span class="line"><span>- docker-compose.yml도 만들어 (Next.js + PostgreSQL + Redis)</span></span>
<span class="line"><span>  - 볼륨 마운트, 네트워크 설정, 환경변수 관리</span></span>
<span class="line"><span>  - dev 프로파일과 prod 프로파일 분리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>추가로:</span></span>
<span class="line"><span>- 각 스테이지에 왜 이렇게 했는지 한 줄 주석</span></span>
<span class="line"><span>- 최종 이미지 크기를 줄이기 위한 구체적 기법 3가지를 README에 정리</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 멀티스테이지 빌드의 올바른 구성</li><li>[ ] node_modules 캐싱 전략</li><li>[ ] standalone 모드 설정 정확성</li><li>[ ] 빌드타임/런타임 환경변수 분리</li><li>[ ] docker-compose의 dev/prod 프로파일 분리</li><li>[ ] .dockerignore 완성도</li></ul><hr><h2 id="so-02-github-actions-ci-cd-파이프라인" tabindex="-1">SO-02. GitHub Actions CI/CD 파이프라인 ⭐⭐⭐ <a class="header-anchor" href="#so-02-github-actions-ci-cd-파이프라인" aria-label="Permalink to &quot;SO-02. GitHub Actions CI/CD 파이프라인 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-1" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-1" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>실전 수준의 CI/CD 파이프라인을 설계하고 작성하는 능력.</p><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Go + React 모노레포를 위한 GitHub Actions CI/CD 파이프라인을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>레포 구조:</span></span></code></pre></div><p>/ ├── backend/ (Go 1.22, Gin framework) ├── frontend/ (React 18, Vite) ├── proto/ (gRPC proto files) ├── deploy/ (K8s manifests) └── scripts/ (유틸 스크립트)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>요구사항:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>워크플로우 1: \`ci.yml\` (PR 시 실행)</span></span>
<span class="line"><span>- 변경된 디렉토리만 감지해서 해당 부분만 빌드/테스트 (dorny/paths-filter)</span></span>
<span class="line"><span>- backend: lint (golangci-lint), test (race condition 감지), build</span></span>
<span class="line"><span>- frontend: lint (eslint), type-check, test (vitest), build</span></span>
<span class="line"><span>- proto: buf lint, buf breaking (하위호환 검사)</span></span>
<span class="line"><span>- 병렬 실행 (backend, frontend, proto 동시에)</span></span>
<span class="line"><span>- PR에 테스트 커버리지 코멘트 자동 추가</span></span>
<span class="line"><span>- 실패 시 Slack 알림</span></span>
<span class="line"><span></span></span>
<span class="line"><span>워크플로우 2: \`deploy.yml\` (main 머지 시 실행)</span></span>
<span class="line"><span>- Docker 이미지 빌드 &amp; ECR 푸시 (backend, frontend 각각)</span></span>
<span class="line"><span>- 이미지 태그: git sha + latest</span></span>
<span class="line"><span>- staging 자동 배포 (K8s manifest의 image tag 업데이트 → ArgoCD sync)</span></span>
<span class="line"><span>- production 배포는 수동 승인 (environment protection rule)</span></span>
<span class="line"><span>- 배포 후 스모크 테스트 (curl로 /health 확인)</span></span>
<span class="line"><span>- 배포 결과 Slack 알림 (성공/실패, 커밋 정보, 소요 시간)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>워크플로우 3: \`scheduled.yml\` (매일 새벽 2시)</span></span>
<span class="line"><span>- 의존성 취약점 스캔 (Go: govulncheck, Node: npm audit)</span></span>
<span class="line"><span>- Docker 이미지 취약점 스캔 (trivy)</span></span>
<span class="line"><span>- 결과를 GitHub Issue로 자동 생성 (critical/high만)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>전체 파일을 \`.github/workflows/\` 하위에 만들어줘.</span></span>
<span class="line"><span>각 워크플로우에 충분한 주석을 달아줘.</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 경로 기반 필터링 (paths-filter) 구현</li><li>[ ] 병렬 job 구성</li><li>[ ] 환경변수 및 시크릿 관리</li><li>[ ] 수동 승인 (environment protection) 구현</li><li>[ ] 스케줄 워크플로우의 이슈 자동 생성</li><li>[ ] Slack 알림 구성</li></ul><hr><h2 id="so-03-서버-트러블슈팅-스크립트" tabindex="-1">SO-03. 서버 트러블슈팅 스크립트 ⭐⭐ <a class="header-anchor" href="#so-03-서버-트러블슈팅-스크립트" aria-label="Permalink to &quot;SO-03. 서버 트러블슈팅 스크립트 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-2" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-2" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>장애 상황에서 빠르게 원인을 진단할 수 있는 스크립트 작성 능력.</p><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Linux 서버 장애 진단용 종합 스크립트를 bash로 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>이름: \`diagnose.sh\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>실행하면 아래 항목을 순서대로 체크하고 보고서를 생성해:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 시스템 기본 정보</span></span>
<span class="line"><span>   - 호스트명, OS 버전, 커널 버전, 업타임</span></span>
<span class="line"><span>   - CPU 모델, 코어 수, 현재 로드 평균</span></span>
<span class="line"><span>   - 메모리 총량/사용량/가용량 (human-readable)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>2. 디스크 상태</span></span>
<span class="line"><span>   - 각 마운트 포인트별 사용률 (90% 이상이면 ⚠️ 경고 표시)</span></span>
<span class="line"><span>   - inode 사용률 체크</span></span>
<span class="line"><span>   - 최근 24시간 내 생성된 1GB 이상 파일 목록</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>3. 네트워크 상태</span></span>
<span class="line"><span>   - 인터페이스별 IP, 상태</span></span>
<span class="line"><span>   - 현재 ESTABLISHED 연결 수 (포트별 상위 10)</span></span>
<span class="line"><span>   - TIME_WAIT 연결 수</span></span>
<span class="line"><span>   - DNS 응답 시간 (google.com 기준)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>4. 프로세스 상태</span></span>
<span class="line"><span>   - CPU 사용률 상위 10 프로세스</span></span>
<span class="line"><span>   - 메모리 사용률 상위 10 프로세스</span></span>
<span class="line"><span>   - zombie 프로세스 목록</span></span>
<span class="line"><span>   - OOM killer 이력 (dmesg)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>5. 서비스 상태</span></span>
<span class="line"><span>   - Docker 실행 중이면: 컨테이너 목록, 비정상 컨테이너, 디스크 사용량</span></span>
<span class="line"><span>   - systemd 실패 서비스 목록</span></span>
<span class="line"><span>   - 최근 1시간 에러 로그 (journalctl, /var/log/syslog)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>6. 보안 체크</span></span>
<span class="line"><span>   - 최근 실패한 SSH 로그인 시도 (상위 IP 5개)</span></span>
<span class="line"><span>   - 30일 이내 만료 예정 SSL 인증서 체크 (certbot)</span></span>
<span class="line"><span>   - 리스닝 포트 목록 중 예상 외 포트</span></span>
<span class="line"><span></span></span>
<span class="line"><span>출력:</span></span>
<span class="line"><span>- 터미널에 컬러 출력 (정상: 초록, 경고: 노랑, 위험: 빨강)</span></span>
<span class="line"><span>- 동시에 \`diagnose_&lt;hostname&gt;_&lt;timestamp&gt;.txt\`에 플레인 텍스트로 저장</span></span>
<span class="line"><span>- --quick 옵션: 1~4번만 실행 (30초 이내 완료)</span></span>
<span class="line"><span>- --json 옵션: JSON 형식으로 출력 (모니터링 시스템 연동용)</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 각 진단 항목의 명령어 정확성</li><li>[ ] 컬러 출력과 플레인 텍스트 동시 저장 구현</li><li>[ ] 경고/위험 판단 기준의 합리성</li><li>[ ] --quick, --json 옵션 처리</li><li>[ ] 에러 처리 (명령어 미존재 시 skip 등)</li><li>[ ] 크로스 배포판 호환성 고려</li></ul><hr><h2 id="so-04-terraform-인프라-코드" tabindex="-1">SO-04. Terraform 인프라 코드 ⭐⭐⭐ <a class="header-anchor" href="#so-04-terraform-인프라-코드" aria-label="Permalink to &quot;SO-04. Terraform 인프라 코드 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-3" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-3" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>IaC(Infrastructure as Code)로 클라우드 인프라를 정의하는 능력.</p><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AWS에서 3-tier 웹 앱 인프라를 Terraform으로 구성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>아키텍처:</span></span>
<span class="line"><span>- VPC: 퍼블릭 서브넷 2개 (AZ 분산), 프라이빗 서브넷 2개 (AZ 분산)</span></span>
<span class="line"><span>- ALB: 퍼블릭 서브넷, HTTPS(443) → HTTP(8080) 포워딩</span></span>
<span class="line"><span>- ECS Fargate: 프라이빗 서브넷, 앱 컨테이너 2개 (최소), 오토스케일링</span></span>
<span class="line"><span>- RDS PostgreSQL: 프라이빗 서브넷, Multi-AZ, 암호화 활성화</span></span>
<span class="line"><span>- ElastiCache Redis: 프라이빗 서브넷</span></span>
<span class="line"><span>- S3: 정적 파일용</span></span>
<span class="line"><span>- CloudWatch: 로그 그룹, CPU 알람 (80% 이상 시 SNS 알림)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일 구조:</span></span></code></pre></div><p>terraform/ ├── main.tf (provider, backend) ├── variables.tf (입력 변수) ├── outputs.tf (출력값) ├── vpc.tf (VPC, 서브넷, IGW, NAT) ├── alb.tf (로드밸런서, 타겟그룹, 리스너) ├── ecs.tf (클러스터, 태스크 정의, 서비스, 오토스케일링) ├── rds.tf (DB 인스턴스, 서브넷 그룹, 보안그룹) ├── redis.tf (ElastiCache) ├── s3.tf (버킷, 정책) ├── monitoring.tf (CloudWatch, SNS) ├── security.tf (보안그룹 통합) └── terraform.tfvars.example</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>요구사항:</span></span>
<span class="line"><span>- 모든 리소스에 태그: Environment, Project, ManagedBy=terraform</span></span>
<span class="line"><span>- 보안그룹: 최소 권한 원칙 (필요한 포트만 오픈)</span></span>
<span class="line"><span>- RDS 비밀번호는 random_password로 생성, SSM Parameter Store에 저장</span></span>
<span class="line"><span>- tfvars.example에 모든 변수의 설명과 예시값</span></span>
<span class="line"><span>- 총 비용 추정치를 주석으로 표시 (월 기준, 서울 리전)</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] Terraform 문법의 정확성</li><li>[ ] 리소스 간 의존성 연결</li><li>[ ] 보안그룹의 최소 권한 설계</li><li>[ ] ECS 오토스케일링 설정</li><li>[ ] 비밀번호 관리 (random_password → SSM)</li><li>[ ] 모듈화/파일 분리의 적절성</li></ul><hr><h2 id="so-05-로그-수집-파이프라인" tabindex="-1">SO-05. 로그 수집 파이프라인 ⭐⭐ <a class="header-anchor" href="#so-05-로그-수집-파이프라인" aria-label="Permalink to &quot;SO-05. 로그 수집 파이프라인 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-4" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-4" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>분산 시스템의 로그를 중앙 집중 수집하는 파이프라인 구성.</p><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Docker Compose로 로그 수집 파이프라인을 구성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>구성:</span></span>
<span class="line"><span>- 로그 생성기: Python 스크립트 (다양한 레벨, 형식의 로그를 초당 10건 생성)</span></span>
<span class="line"><span>- Fluent Bit: 로그 수집 → 파싱 → 라우팅</span></span>
<span class="line"><span>- Elasticsearch: 저장소 (single node, dev 모드)</span></span>
<span class="line"><span>- Kibana: 시각화</span></span>
<span class="line"><span></span></span>
<span class="line"><span>요구사항:</span></span>
<span class="line"><span>1. log_generator.py</span></span>
<span class="line"><span>   - JSON 로그와 plain text 로그를 번갈아 생성</span></span>
<span class="line"><span>   - 레벨: DEBUG(50%), INFO(30%), WARN(10%), ERROR(8%), FATAL(2%)</span></span>
<span class="line"><span>   - 가끔 멀티라인 스택 트레이스 포함 (Python traceback 형태)</span></span>
<span class="line"><span>   - stdout으로 출력</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. fluent-bit.conf</span></span>
<span class="line"><span>   - Docker stdout에서 로그 수집</span></span>
<span class="line"><span>   - JSON 로그는 파싱, plain text는 regex 파싱</span></span>
<span class="line"><span>   - 멀티라인 스택 트레이스 병합</span></span>
<span class="line"><span>   - 로그 레벨별 라우팅: ERROR/FATAL → elasticsearch의 error-* 인덱스</span></span>
<span class="line"><span>   - 나머지 → app-* 인덱스</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. docker-compose.yml</span></span>
<span class="line"><span>   - 모든 서비스 정의</span></span>
<span class="line"><span>   - 헬스체크 설정</span></span>
<span class="line"><span>   - Kibana가 ES 준비 후에 시작하도록 depends_on + healthcheck</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. setup.sh</span></span>
<span class="line"><span>   - docker compose up 후 Kibana 인덱스 패턴 자동 생성</span></span>
<span class="line"><span>   - 샘플 대시보드 import (ndjson 파일)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. README.md — 실행 방법, 아키텍처 다이어그램 (ASCII art)</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] Fluent Bit 설정의 정확성</li><li>[ ] 멀티라인 파싱 구현</li><li>[ ] 레벨별 라우팅 구현</li><li>[ ] Docker Compose 의존성 관리</li><li>[ ] log_generator.py의 현실적 로그 패턴</li><li>[ ] 전체 실행 가능성</li></ul><hr><h2 id="so-06-nginx-리버스-프록시-ssl" tabindex="-1">SO-06. Nginx 리버스 프록시 + SSL ⭐ <a class="header-anchor" href="#so-06-nginx-리버스-프록시-ssl" aria-label="Permalink to &quot;SO-06. Nginx 리버스 프록시 + SSL :star:&quot;">​</a></h2><h3 id="시나리오-배경-5" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-5" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>기본적인 웹 서버 구성 능력.</p><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nginx 리버스 프록시 설정을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>환경:</span></span>
<span class="line"><span>- 도메인: app.example.com, api.example.com, admin.example.com</span></span>
<span class="line"><span>- 백엔드 서비스 (Docker 네트워크 내):</span></span>
<span class="line"><span>  - frontend: port 3000</span></span>
<span class="line"><span>  - api: port 8080</span></span>
<span class="line"><span>  - admin: port 3001</span></span>
<span class="line"><span></span></span>
<span class="line"><span>요구사항:</span></span>
<span class="line"><span>1. nginx.conf</span></span>
<span class="line"><span>   - app.example.com → frontend:3000</span></span>
<span class="line"><span>   - api.example.com → api:8080 (CORS 헤더 추가, preflight 처리)</span></span>
<span class="line"><span>   - admin.example.com → admin:3001 (IP 화이트리스트: 사무실 IP만)</span></span>
<span class="line"><span>   - HTTP → HTTPS 자동 리다이렉트</span></span>
<span class="line"><span>   - SSL 설정 (Let&#39;s Encrypt certbot 연동)</span></span>
<span class="line"><span>   - 보안 헤더 (HSTS, X-Content-Type-Options 등)</span></span>
<span class="line"><span>   - gzip 압축</span></span>
<span class="line"><span>   - WebSocket 프록시 지원 (/ws 경로)</span></span>
<span class="line"><span>   - rate limiting (API: 초당 100요청, Admin: 초당 20요청)</span></span>
<span class="line"><span>   - 커스텀 에러 페이지 (502, 503, 504)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. docker-compose.yml (Nginx + certbot 자동갱신)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. init-ssl.sh (초기 인증서 발급 스크립트)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 성능 튜닝 설정에 대한 주석 설명</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] server 블록 분리의 정확성</li><li>[ ] CORS preflight 처리</li><li>[ ] IP 화이트리스트 구현</li><li>[ ] SSL 설정 (프로토콜, 암호화 스위트)</li><li>[ ] WebSocket 프록시 설정</li><li>[ ] rate limiting 구현</li></ul><hr><h2 id="so-07-k8s-매니페스트-헬름-차트" tabindex="-1">SO-07. K8s 매니페스트 + 헬름 차트 ⭐⭐⭐ <a class="header-anchor" href="#so-07-k8s-매니페스트-헬름-차트" aria-label="Permalink to &quot;SO-07. K8s 매니페스트 + 헬름 차트 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-6" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-6" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>Kubernetes 리소스를 관리하는 실전 수준의 설정 작성.</p><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Spring Boot 앱을 위한 Kubernetes 매니페스트와 Helm 차트를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>앱 정보:</span></span>
<span class="line"><span>- 이미지: myregistry/order-service:latest</span></span>
<span class="line"><span>- 포트: 8080 (HTTP), 8081 (gRPC), 9090 (metrics/Prometheus)</span></span>
<span class="line"><span>- 환경변수: DB_HOST, DB_PORT, DB_NAME, DB_USER, DB_PASSWORD, REDIS_URL, JWT_SECRET</span></span>
<span class="line"><span>- 리소스: CPU 요청 250m/제한 500m, 메모리 요청 512Mi/제한 1Gi</span></span>
<span class="line"><span></span></span>
<span class="line"><span>매니페스트 (k8s/ 디렉토리):</span></span>
<span class="line"><span>1. Deployment</span></span>
<span class="line"><span>   - 레플리카 3, RollingUpdate (maxSurge 1, maxUnavailable 0)</span></span>
<span class="line"><span>   - readinessProbe: /actuator/health (10초 간격)</span></span>
<span class="line"><span>   - livenessProbe: /actuator/health/liveness (15초 간격, failureThreshold 3)</span></span>
<span class="line"><span>   - startupProbe: /actuator/health (5초 간격, failureThreshold 30)</span></span>
<span class="line"><span>   - 시크릿은 외부 Secret 리소스에서 envFrom으로 주입</span></span>
<span class="line"><span>   - podAntiAffinity: 같은 노드에 2개 이상 배치 금지</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>2. Service (ClusterIP: 8080, gRPC: 8081)</span></span>
<span class="line"><span>3. HPA (CPU 70% → 3~10, 메모리 80% → 스케일업)</span></span>
<span class="line"><span>4. PodDisruptionBudget (minAvailable: 2)</span></span>
<span class="line"><span>5. NetworkPolicy (ingress: 같은 네임스페이스 + 인그레스 컨트롤러만)</span></span>
<span class="line"><span>6. ServiceMonitor (Prometheus Operator 용)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Helm 차트 (helm/order-service/):</span></span>
<span class="line"><span>- values.yaml: 환경별 오버라이드 가능하도록</span></span>
<span class="line"><span>- values-staging.yaml, values-production.yaml</span></span>
<span class="line"><span>- templates/에 위 매니페스트 템플릿화</span></span>
<span class="line"><span>- _helpers.tpl에 공통 레이블, 이름 생성 헬퍼</span></span>
<span class="line"><span>- NOTES.txt에 설치 후 안내 메시지</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] Probe 3종 설정의 정확성</li><li>[ ] podAntiAffinity 표현식</li><li>[ ] HPA 설정</li><li>[ ] NetworkPolicy 규칙</li><li>[ ] Helm 템플릿 문법</li><li>[ ] 환경별 values 분리</li></ul>`,64)])])}const b=s(e,[["render",i]]);export{u as __pageData,b as default};
